mapper.select:
select id as id,image_url as imageUrl
 from
`t_nail_order`


			id = #{id}


			and image_url = #{imageUrl}


			and image_name = #{imageName}


			and username = #{username}


			and third_flag = #{thirdFlag}


			and comefrom = #{comefrom}


order by id limit 1

SELECT t.id as id, t.username as username, t.mobile as mobile,
t.image_url as imageUrl, t.image_name as imageName, t.comefrom as comefrom, t.nail_config_id as nailConfigId, t.nail_pictureframe_Id as nailPictureFrameId,
nf.nail_type as nailType, ifnull(t.third_flag,0) as thirdFlag, tnp.color_name as colorName, t.create_date as createDate, t.update_date as updateDate FROM t_nail_order t left join t_nail_config nf on t.nail_config_id = nf.id left join t_nail_pictureframe tnp on t.nail_pictureframe_Id = tnp.id
t.username like '%${entity.username}%'
and t.image_name like '%${entity.imageName}%'
and t.mobile like '%${entity.mobile}%'
and (t.username like '%${entity.searchValue}%' or t.image_name like '%${entity.searchValue}%' or t.mobile like '%${entity.searchValue}%')
and t.comefrom = #{entity.comefrom}
and t.nail_config_id = #{entity.nailConfigId}
and t.nail_pictureframe_Id = #{entity.nailPictureFrameId}
ORDER by t.id desc limit ${page.begin},${page.limit}

SELECT count(1) FROM `t_nail_order` t




				t.username  like '%${entity.username}%'


					and t.image_name  like '%${entity.imageName}%'


					and t.mobile like '%${entity.mobile}%'




				and 
				(t.username like '%${entity.searchValue}%' or t.image_name  like '%${entity.searchValue}%' or t.mobile like '%${entity.searchValue}%')





			and t.comefrom = #{entity.comefrom}


			and t.nail_config_id = #{entity.nailConfigId}


			and t.nail_pictureframe_Id = #{entity.nailPictureFrameId}

SELECT t.id as id, t.username as username, t.mobile as mobile, t.step as step, ifnull(t.current_step ,'') as currentStep, t.image_url as imageUrl, t.result_image_url as resultImageUrl, t.image_name as imageName, t.comefrom as comefrom, t.nail_config_id as nailConfigId, t.nail_pictureframe_Id as nailPictureFrameId, t.nail_count_detail as nailCountDetail, t.width as width, t.height as height, nf.nail_type as nailType, tnp.color_name as colorName, ifnull(tns.status,0) as status, t.create_date as createDate, t.update_date as updateDate FROM t_nail_order t left join t_nail_config nf on t.nail_config_id = nf.id left join t_nail_pictureframe tnp on t.nail_pictureframe_Id = tnp.id left join t_nail_secret tns on t.id = tns.order_id
t.mobile = #{keyword} OR t.image_name = #{keyword}
t.id = #{id}
ORDER by t.id desc
